<?php/** * Template functions for AquaLuxe theme * * @package AquaLuxe * @since 1.0.0 */// Prevent direct access to this fileif (!defined('ABSPATH')) {    exit;}/** * Display site logo * * @param array $args * @return void */function aqualuxe_site_logo($args = array()) {    $defaults = array(        'class' => 'site-logo',        'echo' => true,    );        $args = wp_parse_args($args, $defaults);        $logo_html = '';    $has_custom_logo = has_custom_logo();        if ($has_custom_logo) {        $logo_html = get_custom_logo();    } else {        $logo_html = '<a href="' . esc_url(home_url('/')) . '" class="' . esc_attr($args['class']) . '" rel="home">';        $logo_html .= '<span class="site-title">' . esc_html(get_bloginfo('name')) . '</span>';        $logo_html .= '</a>';    }        if ($args['echo']) {        echo $logo_html;    } else {        return $logo_html;    }}/** * Display site navigation * * @param string $location * @param array $args * @return void */function aqualuxe_navigation($location = 'primary', $args = array()) {    $defaults = array(        'theme_location' => $location,        'container' => 'nav',        'container_class' => 'aqualuxe-navigation',        'container_id' => 'aqualuxe-navigation-' . $location,        'menu_class' => 'aqualuxe-menu',        'menu_id' => 'aqualuxe-menu-' . $location,        'fallback_cb' => 'aqualuxe_navigation_fallback',        'echo' => true,        'walker' => new AquaLuxe_Walker_Nav_Menu(),    );        $args = wp_parse_args($args, $defaults);        if ($args['echo']) {        wp_nav_menu($args);    } else {        return wp_nav_menu($args);    }}/** * Navigation fallback * * @param array $args * @return void */function aqualuxe_navigation_fallback($args) {    echo '<nav class="' . esc_attr($args['container_class']) . '" id="' . esc_attr($args['container_id']) . '">';    echo '<ul class="' . esc_attr($args['menu_class']) . '" id="' . esc_attr($args['menu_id']) . '">';        wp_list_pages(array(        'title_li' => '',        'depth' => 1,    ));        echo '</ul>';    echo '</nav>';}/** * Display language switcher * * @param array $args * @return void */function aqualuxe_language_switcher($args = array()) {    $defaults = array(        'class' => 'aqualuxe-language-switcher',        'echo' => true,    );        $args = wp_parse_args($args, $defaults);        $languages = aqualuxe_get_available_languages();        if (count($languages) <= 1) {        return;    }        $html = '<div class="' . esc_attr($args['class']) . '">';    $html .= '<div class="aqualuxe-language-switcher-toggle">';        foreach ($languages as $language) {        if ($language['active']) {            $html .= '<span class="aqualuxe-language-switcher-current">';                        if (!empty($language['flag'])) {                $html .= '<img src="' . esc_url($language['flag']) . '" alt="' . esc_attr($language['name']) . '" class="aqualuxe-language-switcher-flag" />';            }                        $html .= '<span class="aqualuxe-language-switcher-code">' . esc_html(strtoupper($language['code'])) . '</span>';            $html .= '</span>';            break;        }    }        $html .= '</div>';        $html .= '<div class="aqualuxe-language-switcher-dropdown">';    $html .= '<ul class="aqualuxe-language-switcher-list">';        foreach ($languages as $language) {        $html .= '<li class="aqualuxe-language-switcher-item' . ($language['active'] ? ' active' : '') . '">';        $html .= '<a href="' . esc_url($language['url']) . '" class="aqualuxe-language-switcher-link">';                if (!empty($language['flag'])) {            $html .= '<img src="' . esc_url($language['flag']) . '" alt="' . esc_attr($language['name']) . '" class="aqualuxe-language-switcher-flag" />';        }                $html .= '<span class="aqualuxe-language-switcher-name">' . esc_html($language['name']) . '</span>';        $html .= '<span class="aqualuxe-language-switcher-code">' . esc_html(strtoupper($language['code'])) . '</span>';        $html .= '</a>';        $html .= '</li>';    }        $html .= '</ul>';    $html .= '</div>';    $html .= '</div>';        if ($args['echo']) {        echo $html;    } else {        return $html;    }}/** * Display currency switcher * * @param array $args * @return void */function aqualuxe_currency_switcher($args = array()) {    if (!aqualuxe_is_woocommerce_active()) {        return;    }        $defaults = array(        'class' => 'aqualuxe-currency-switcher',        'echo' => true,    );        $args = wp_parse_args($args, $defaults);        $currencies = aqualuxe_get_available_currencies();        if (count($currencies) <= 1) {        return;    }        $html = '<div class="' . esc_attr($args['class']) . '">';    $html .= '<div class="aqualuxe-currency-switcher-toggle">';        foreach ($currencies as $currency) {        if ($currency['active']) {            $html .= '<span class="aqualuxe-currency-switcher-current">';            $html .= '<span class="aqualuxe-currency-switcher-symbol">' . esc_html($currency['symbol']) . '</span>';            $html .= '<span class="aqualuxe-currency-switcher-code">' . esc_html($currency['code']) . '</span>';            $html .= '</span>';            break;        }    }        $html .= '</div>';        $html .= '<div class="aqualuxe-currency-switcher-dropdown">';    $html .= '<ul class="aqualuxe-currency-switcher-list">';        foreach ($currencies as $currency) {        $html .= '<li class="aqualuxe-currency-switcher-item' . ($currency['active'] ? ' active' : '') . '">';                if (function_exists('wcml_cs_get_currency_selector_form')) {            $html .= wcml_cs_get_currency_selector_form($currency['code']);        } else {            $html .= '<a href="' . esc_url(add_query_arg('currency', $currency['code'])) . '" class="aqualuxe-currency-switcher-link">';            $html .= '<span class="aqualuxe-currency-switcher-symbol">' . esc_html($currency['symbol']) . '</span>'; 